const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle content array format from Anthropic
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Clean JSON from any markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let aiScore;
try {
  aiScore = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse AI response: ${error.message}. Response was: ${cleanText}`);
}

// Pull job and search context from upstream
const jobData = $('Skip Already Seen Jobs').item.json;
const scoreThreshold = jobData.searchContext?.searchParams?.scoreThreshold || 70;

return {
  json: {
    job: jobData.job,
    searchContext: jobData.searchContext,
    aiScore,
    scoreThreshold,
    meetsThreshold: (aiScore.totalScore || 0) >= scoreThreshold,
    processedAt: new Date().toISOString()
  }
};

