const jobData = $('Parse AI Score and Decide').item.json;
const applyResponse = $('Submit Easy Apply Application').item.json;
const connectionResponse = $('Send Recruiter Connection Request').item.json;

const applicationSuccess = !applyResponse.error && (applyResponse.status === 200 || applyResponse.id);
const connectionSuccess = !connectionResponse.error && (connectionResponse.id || connectionResponse.createdAt);

return {
  json: {
    status: 'APPLIED',
    jobId: jobData.job.jobId,
    jobTitle: jobData.job.title,
    company: jobData.job.companyName,
    location: jobData.job.location,
    jobUrl: jobData.job.jobUrl,
    salary: jobData.job.salary,
    aiScore: jobData.aiScore.totalScore,
    matchedSkills: jobData.aiScore.matchedSkills,
    missingSkills: jobData.aiScore.missingSkills,
    pros: jobData.aiScore.pros,
    cons: jobData.aiScore.cons,
    applicationSubmitted: applicationSuccess,
    connectionRequestSent: connectionSuccess,
    appliedAt: new Date().toISOString(),
    requestId: jobData.searchContext.metadata.requestId
  }
};

const jobData = $input.item.json;

return {
  json: {
    status: 'SKIPPED_LOW_SCORE',
    jobId: jobData.job.jobId,
    jobTitle: jobData.job.title,
    company: jobData.job.companyName,
    location: jobData.job.location,
    jobUrl: jobData.job.jobUrl,
    salary: jobData.job.salary,
    aiScore: jobData.aiScore.totalScore,
    scoreThreshold: jobData.scoreThreshold,
    matchedSkills: jobData.aiScore.matchedSkills,
    missingSkills: jobData.aiScore.missingSkills,
    reason: `Score ${jobData.aiScore.totalScore} below threshold of ${jobData.scoreThreshold}`,
    processedAt: new Date().toISOString(),
    requestId: jobData.searchContext.metadata.requestId
  }
};
